const REPUTATION_BADGES={legendary:{minScore:50,name:"Lendário",icon:"crown",color:"#ffd700",glow:!0},veteran:{minScore:25,name:"Veterano",icon:"star",color:"#e5e4e2",glow:!1},experienced:{minScore:10,name:"Experiente",icon:"shield-check",color:"#daa520",glow:!1},trusted:{minScore:5,name:"Confiável",icon:"shield",color:"#c0c0c0",glow:!1},beginner:{minScore:1,name:"Iniciante",icon:"award",color:"#cd7f32",glow:!1},newbie:{minScore:-1/0,name:"Novato",icon:"user",color:"#6b7280",glow:!1}},VOTE_COOLDOWN_DAYS=30;class ReputationService{constructor(){this.cache=new Map,this.voteCooldowns=new Map}async getReputation(e){if(this.cache.has(e))return this.cache.get(e);const t=await nocoDBService.getUserReputation(e);return this.cache.set(e,t),t}getBadge(e){for(const[t,n]of Object.entries(REPUTATION_BADGES))if(e>=n.minScore)return{...n,key:t};return{...REPUTATION_BADGES.newbie,key:"newbie"}}async canVote(e){return await nocoDBService.canVoteFor(e)}async vote(e,t,n="",a=""){if(!nocoDBService.isLoggedIn())throw new Error("Faça login para votar");try{return await nocoDBService.castVote(e,t,n,a),this.cache.delete(e),!0}catch(e){throw e}}renderBadge(e,t="small"){const n=this.getBadge(e),a="large"===t?"reputation-badge-lg":"";return`\n            <span class="reputation-badge reputation-${n.key} ${a}" ${n.glow?'data-glow="true"':""}>\n                <i data-lucide="${n.icon}"></i>\n                ${"large"===t?`<span>${n.name}</span>`:""}\n            </span>\n        `}renderBadgeWithTooltip(e,t="small"){const n=this.getBadge(e.score),a=`${e.positives} positivos, ${e.negatives} negativos`;return`\n            <span class="reputation-badge reputation-${n.key} has-tooltip" title="${a}">\n                <i data-lucide="${n.icon}"></i>\n                ${"large"===t?`<span>${n.name}</span>`:""}\n            </span>\n        `}async openVoteModal(e,t){if(!nocoDBService.isLoggedIn())return void showToast("Faça login para votar","error");const n=await this.canVote(e);n.canVote?(document.getElementById("vote-modal").dataset.userId=e,document.getElementById("vote-target-name").textContent=t,document.getElementById("vote-reason").value="",document.getElementById("vote-reference").value="",document.querySelectorAll(".vote-type-btn").forEach(e=>e.classList.remove("selected")),openModal("vote-modal")):"self_vote"===n.reason?showToast("Você não pode votar em si mesmo","error"):"cooldown"===n.reason?showToast(`Aguarde ${n.daysLeft} dias para votar novamente neste usuário`,"warning"):showToast("Não é possível votar neste momento","error")}async submitVote(){const e=parseInt(document.getElementById("vote-modal").dataset.userId),t=document.querySelector(".vote-type-btn.selected")?.dataset.type,n=document.getElementById("vote-reason").value.trim(),a=document.getElementById("vote-reference").value.trim();if(t)try{setButtonLoading(event.target,!0),await this.vote(e,t,n,a),showToast("Voto registrado!","success"),closeModal("vote-modal"),setButtonLoading(event.target,!1)}catch(e){showToast(e.message||"Erro ao votar","error"),setButtonLoading(event.target,!1)}else showToast("Selecione Positivo ou Negativo","error")}async renderUserReputation(e){const t=document.getElementById("user-reputation-view");if(t)try{const n=await nocoDBService.getUserById(e);if(!n)return void(t.innerHTML="<p>Usuário não encontrado</p>");const a=await this.getReputation(e),o=this.getBadge(a.score),s=nocoDBService.getCurrentUser()?.id===e;let r=[];s&&(r=await nocoDBService.getReceivedVotes(e)),t.innerHTML=`\n                <div class="reputation-profile">\n                    <div class="reputation-header">\n                        ${renderAvatar(n.avatarId,"large")}\n                        <div class="reputation-info">\n                            <h2>${escapeHtml(n.displayName)}</h2>\n                            <div class="reputation-badge-large reputation-${o.key}" ${o.glow?'data-glow="true"':""}>\n                                <i data-lucide="${o.icon}"></i>\n                                <span>${o.name}</span>\n                            </div>\n                        </div>\n                    </div>\n\n                    <div class="reputation-stats">\n                        <div class="rep-stat rep-score">\n                            <span class="rep-stat-value">${a.score}</span>\n                            <span class="rep-stat-label">Score</span>\n                        </div>\n                        <div class="rep-stat rep-positive">\n                            <span class="rep-stat-value">${a.positives}</span>\n                            <span class="rep-stat-label">Positivos</span>\n                        </div>\n                        <div class="rep-stat rep-negative">\n                            <span class="rep-stat-value">${a.negatives}</span>\n                            <span class="rep-stat-label">Negativos</span>\n                        </div>\n                    </div>\n\n                    ${s?"":`\n                        <button class="btn btn-primary" onclick="reputationService.openVoteModal(${e}, '${escapeHtml(n.displayName)}')">\n                            <i data-lucide="thumbs-up"></i>\n                            Dar Voto\n                        </button>\n                    `}\n\n                    ${s&&r.length>0?`\n                        <div class="votes-history">\n                            <h3>Histórico de Votos Recebidos</h3>\n                            ${r.map(e=>this.renderVoteItem(e)).join("")}\n                        </div>\n                    `:""}\n                </div>\n            `,refreshIcons(t)}catch(e){console.error("Error rendering reputation:",e),t.innerHTML="<p>Erro ao carregar reputação</p>"}}renderVoteItem(e){const t="positive"===e.vote_type,n=new Date(e.created_at).toLocaleDateString("pt-BR");return`\n            <div class="vote-item vote-${e.vote_type}">\n                <span class="vote-icon">\n                    <i data-lucide="${t?"thumbs-up":"thumbs-down"}"></i>\n                </span>\n                <div class="vote-details">\n                    <span class="vote-date">${n}</span>\n                    ${e.reason?`<p class="vote-reason">${escapeHtml(e.reason)}</p>`:""}\n                    ${e.trade_reference?`<p class="vote-reference">Ref: ${escapeHtml(e.trade_reference)}</p>`:""}\n                </div>\n            </div>\n        `}renderBadgesLegend(){let e='<div class="badges-legend">';for(const[t,n]of Object.entries(REPUTATION_BADGES))"newbie"===t&&n.minScore===-1/0||(e+=`\n                <div class="badge-legend-item">\n                    <span class="reputation-badge reputation-${t}" ${n.glow?'data-glow="true"':""}>\n                        <i data-lucide="${n.icon}"></i>\n                    </span>\n                    <span class="badge-name">${n.name}</span>\n                    <span class="badge-requirement">${n.minScore}+ pontos</span>\n                </div>\n            `);return e+="</div>",e}}function getReputationBadge(e){return reputationService.getBadge(e)}const reputationService=new ReputationService;document.addEventListener("DOMContentLoaded",()=>{document.querySelectorAll(".vote-type-btn").forEach(e=>{e.addEventListener("click",()=>{document.querySelectorAll(".vote-type-btn").forEach(e=>e.classList.remove("selected")),e.classList.add("selected")})})}),"undefined"!=typeof module&&module.exports&&(module.exports={ReputationService:ReputationService,reputationService:reputationService,REPUTATION_BADGES:REPUTATION_BADGES,getReputationBadge:getReputationBadge});